package ua.university.sms.service;
import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.EnrollmentDtos.*;import ua.university.sms.model.entity.*;import ua.university.sms.repository.*;import java.util.*;
@Service public class EnrollmentService{private final EnrollmentRepository repo;private final StudentRepository students;private final CourseRepository courses;public EnrollmentService(EnrollmentRepository repo,StudentRepository students,CourseRepository courses){this.repo=repo;this.students=students;this.courses=courses;}public Response create(Request r){if(repo.existsByStudentIdAndCourseId(r.studentId(),r.courseId()))throw new IllegalStateException("Student is already enrolled in this course");Enrollment e=new Enrollment();apply(e,r);return dto(repo.save(e));}public Response get(Long id){return dto(find(id));}public List<Response> list(){return repo.findAll().stream().map(this::dto).toList();}public Response update(Long id,Request r){Enrollment e=find(id);apply(e,r);return dto(repo.save(e));}public Response setPaid(Long id,PaymentRequest r){Enrollment e=find(id);e.setPaid(r.paid());return dto(repo.save(e));}public Response setGrade(Long id,GradeRequest r){Enrollment e=find(id);e.setGrade(r.grade());return dto(repo.save(e));}public void delete(Long id){repo.delete(find(id));}public Double averageByCourse(Long courseId){return repo.averageGpaByCourse(courseId);}public Double averageBySemester(String semester){return repo.averageGpaBySemester(semester);}private Enrollment find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Enrollment not found: "+id));}private void apply(Enrollment e,Request r){Student s=students.findById(r.studentId()).orElseThrow(()->new NotFoundException("Student not found: "+r.studentId()));Course c=courses.findById(r.courseId()).orElseThrow(()->new NotFoundException("Course not found: "+r.courseId()));e.setStudent(s);e.setCourse(c);e.setPaid(r.paid());e.setGrade(r.grade());}private Response dto(Enrollment e){return new Response(e.getId(),e.getStudent().getId(),e.getStudent().getFullName(),e.getCourse().getId(),e.getCourse().getTitle(),e.isPaid(),e.getGrade(),e.getEnrolledAt());}}
